class Solution:
    def findWinners(self, matches):
        """
        :type matches: List[List[int]]
        :rtype: List[List[int]]
        """
        loss_count = {}
        all_players = set()

        for winner, loser in matches:
            all_players.add(winner)
            all_players.add(loser)

            loss_count[loser] = loss_count.get(loser, 0) + 1
            if winner not in loss_count:
                loss_count[winner] = 0

        zero_losses = []
        one_loss = []

        for player in all_players:
            losses = loss_count.get(player, 0)
            if losses == 0:
                zero_losses.append(player)
            elif losses == 1:
                one_loss.append(player)

        return [sorted(zero_losses), sorted(one_loss)]
